		log.Fatal("Missing required environment variables")
	}

	// Remove @gmail.com if it exists in MAGICBELL_EMAIL
	username := strings.TrimSuffix(emailBase, "@gmail.com")

	// Wait, the prompt says exactly `${MAGICBELL_EMAIL}+${ZEALT_RUN_ID}@gmail.com`
	// Let's check if the prompt meant MAGICBELL_EMAIL is the username or the full email.
	// If it meant full email, then the literal string might be what they want.
	// But if it's "user email not valid" error from MagicBell, it means MagicBell validates the email format.
	// `username@gmail.com+runid@gmail.com` is NOT a valid email.
	// So it MUST be `username+runid@gmail.com`.
	// Let's try `username+runid@gmail.com`.
	userEmail := fmt.Sprintf("%s+%s@gmail.com", username, runID)

	// Generate User JWT
	token := jwt.NewWithClaims(jwt.SigningMethodHS256, jwt.MapClaims{
		"user_email": userEmail,
		"api_key":    apiKey,
		"exp":        time.Now().Add(time.Hour * 24).Unix(),
		"iat":        time.Now().Unix(),
	})

	tokenString, err := token.SignedString([]byte(secretKey))
	if err != nil {
		log.Fatalf("Failed to sign token: %v", err)
	}

	// Initialize UserClient
	config := clientconfig.NewConfig()
	config.SetAccessToken(tokenString)

	userClient := client.NewClient(config)

	// Fetch notifications
	params := notifications.ListNotificationsRequestParams{}
	res, clientErr := userClient.Notifications.ListNotifications(context.Background(), params)
	if clientErr != nil {
		log.Fatalf("Failed to list notifications: %v, Body: %s", clientErr.Error(), string(clientErr.Body))
	}

	readCount := 0
	unreadCount := 0

	for _, notif := range res.Data.GetData() {
		if notif.ReadAt != nil && !notif.ReadAt.IsNull {
			readCount++
		} else {
			unreadCount++
		}
	}

	output := fmt.Sprintf("Read: %d\nUnread: %d\n", readCount, unreadCount)

